mapper.select:
SELECT r.* FROM dorm_room r
                    INNER JOIN dorm_building b ON r.building_id = b.id
                    INNER JOIN dorm_floor f ON r.floor_id = f.id
WHERE r.building_id = #{buildingId}
  AND r.gender = #{gender}
  AND r.usage_type = #{usageType}
  AND r.status = 20              AND r.safety_level = 1          AND b.status = 20              AND f.status = 20              AND r.resource_status IN (21, 23, 24, 25) AND r.del_flag = '0'
ORDER BY r.resource_status DESC, r.room_no ASC

SELECT resource_status AS resStatus, COUNT(id) AS count FROM dorm_room WHERE del_flag = '0'
AND building_id = #{buildingId}
AND campus_id = #{campusId}
GROUP BY resource_status
